// Shape uploaded archive blocks into what the site's tape module expects.
// Filenames come from tape-recorder-azuracast.sh: Archive/lounge-YYYY-MM-DD-HH00.ext
// AzuraCast's Files API returns a JSON array, which n8n splits into one
// item per file — handle both that and the unsplit-array shape.
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && j.path) rows.push(j);
}
const blocks = [];
for (const f of rows) {
  if (!f.path || !f.path.startsWith('Archive/')) continue;
  const m = f.path.match(/lounge-(\d{4}-\d{2}-\d{2})-(\d{2})00/);
  if (!m || !f.unique_id) continue;
  blocks.push({
    url: 'https://streaming.mellowmountainradio.com/api/station/1/ondemand/download/' + f.unique_id,
    date: m[1],
    start: +m[2],
  });
}
return [{ json: { ok: true, blocks } }];

// Anything in Archive/ past 14 days gets pruned — the statutory maximum.
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && j.path) rows.push(j);
}
const cutoff = Math.floor(Date.now() / 1000) - 14 * 24 * 3600;
const stale = [];
for (const f of rows) {
  if (!f.path || !f.path.startsWith('Archive/')) continue;
  if ((f.uploaded_at || 0) < cutoff) stale.push({ id: f.id });
}
return stale;
